use std::collections::HashMap;
use std::fs::File;
use std::io::{BufRead, BufReader};
use std::path::PathBuf;

use clap::Parser;

use ccs_viewer::types::Record;

#[derive(Parser)]
#[command(version, about = "Claude Code session JSONL viewer")]
struct Cli {
    /// Session JSONL files to process
    #[arg(required = true)]
    files: Vec<PathBuf>,
}

fn record_label(record: &Record) -> &'static str {
    match record {
        Record::FileHistorySnapshot(_) => "file-history-snapshot",
        Record::User(_) => "user",
        Record::Assistant(_) => "assistant",
        Record::Progress(_) => "progress",
        Record::LastPrompt(_) => "last-prompt",
        Record::QueueOperation(_) => "queue-operation",
        Record::System(_) => "system",
        Record::CustomTitle(_) => "custom-title",
        Record::AgentName(_) => "agent-name",
    }
}

fn main() {
    let cli = Cli::parse();
    let mut has_errors = false;

    for path in &cli.files {
        let file = File::open(path).unwrap_or_else(|e| {
            eprintln!("Error opening {}: {e}", path.display());
            std::process::exit(1);
        });

        let reader = BufReader::new(file);
        let mut counts: HashMap<&str, usize> = HashMap::new();
        let mut errors: Vec<(usize, String)> = Vec::new();

        for (i, line) in reader.lines().enumerate() {
            let line = line.unwrap_or_else(|e| {
                eprintln!("Error reading line {}: {e}", i + 1);
                std::process::exit(1);
            });
            if line.trim().is_empty() {
                continue;
            }
            match serde_json::from_str::<Record>(&line) {
                Ok(record) => {
                    *counts.entry(record_label(&record)).or_insert(0) += 1;
                }
                Err(e) => {
                    errors.push((i + 1, format!("{e}")));
                }
            }
        }

        let total: usize = counts.values().sum();
        println!("Deserialized {total} records from {}", path.display());
        for (label, count) in &counts {
            println!("  {label}: {count}");
        }
        if !errors.is_empty() {
            has_errors = true;
            eprintln!("\n{} error(s):", errors.len());
            for (line_num, msg) in &errors {
                eprintln!("  line {line_num}: {msg}");
            }
        }
    }

    if has_errors {
        std::process::exit(1);
    }
}

